import React from 'react';
import { X } from 'lucide-react';

const DetailedModal = ({ onClose, history, title, filterId }) => {
  const getPrevention = (type) => {
    switch(type) {
      case 'DDoS': return 'Rate limiting & Cloudflare proxy filtering.';
      case 'Ransomware': return 'Air-gapped backups & macro blocking.';
      case 'Phishing': return 'DMARC validation & employee training.';
      case 'Port Scan': return 'Configure firewall to drop unsolicited TCP SYN.';
      case 'Botnet': return 'Null-route C2 server IPs.';
      case 'Zero-Day Exploit': return 'Heuristic analysis & quarantine.';
      default: return 'Standard firewall rules applied.';
    }
  };

  // Base data: get all actual attacks from history
  let threatLogs = history ? history.filter(item => item.attack_type !== 'Normal') : [];

  // 🔥 THE SMART FILTER: Changes the data based on which block you clicked! 🔥
  if (filterId === 'active') {
    // Only show threats marked as CRITICAL
    threatLogs = threatLogs.filter(t => t.severity === 'CRITICAL');
  } else if (filterId === 'blocked') {
    // Show attacks that CortexShield automatically mitigated
    threatLogs = threatLogs.filter(t => t.attack_type !== 'Normal');
  } else if (filterId === 'regions') {
    // Sort by country so you can see the affected regions clearly
    threatLogs = threatLogs.sort((a, b) => a.origin_country.localeCompare(b.origin_country));
  }

  return (
    <div style={{ position: 'fixed', top: 0, left: 0, width: '100%', height: '100%', background: 'rgba(11, 15, 25, 0.9)', display: 'flex', justifyContent: 'center', alignItems: 'center', zIndex: 1000 }}>
      <div style={{ background: '#1a1f2e', padding: '30px', borderRadius: '12px', width: '90%', maxHeight: '80vh', overflowY: 'auto', border: '1px solid #3b82f6', boxShadow: '0 0 30px rgba(59, 130, 246, 0.2)' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '20px', borderBottom: '1px solid #334155', paddingBottom: '15px' }}>
          
          {/* Dynamically changes the Title to match the block you clicked! */}
          <h2 style={{ margin: 0, color: '#00ff9d' }}>Log Viewer: {title || 'Threat Database'}</h2>
          
          <button onClick={onClose} style={{ background: 'transparent', border: 'none', cursor: 'pointer', color: '#ef4444' }}><X size={28} /></button>
        </div>
        
        {threatLogs.length === 0 ? (
          <p style={{ color: '#94a3b8', textAlign: 'center', padding: '20px' }}>No specific data found for this filter yet. Awaiting telemetry...</p>
        ) : (
          <table style={{ width: '100%', textAlign: 'left', borderCollapse: 'collapse', color: 'white', fontSize: '14px' }}>
            <thead>
              <tr style={{ background: '#0b0f19', color: '#94a3b8' }}>
                <th style={{ padding: '12px' }}>Timestamp</th>
                <th style={{ padding: '12px' }}>Attack Type</th>
                <th style={{ padding: '12px' }}>Attacker IP</th>
                <th style={{ padding: '12px' }}>Origin Country</th>
                <th style={{ padding: '12px' }}>AI Threat Score</th>
                <th style={{ padding: '12px' }}>Automated Prevention</th>
              </tr>
            </thead>
            <tbody>
              {threatLogs.map((threat, i) => (
                <tr key={i} style={{ borderBottom: '1px solid #334155' }}>
                  <td style={{ padding: '15px 12px', color: '#cbd5e1' }}>{new Date(threat.timestamp * 1000).toLocaleTimeString()}</td>
                  <td style={{ padding: '15px 12px', color: '#ef4444', fontWeight: 'bold' }}>{threat.attack_type}</td>
                  <td style={{ padding: '15px 12px', fontFamily: 'monospace', color: '#cbd5e1' }}>{threat.source_ip}</td>
                  <td style={{ padding: '15px 12px' }}>{threat.origin_country}</td>
                  <td style={{ padding: '15px 12px', color: '#eab308' }}>{threat.threat_score}</td>
                  <td style={{ padding: '15px 12px', color: '#00ff9d' }}>{getPrevention(threat.attack_type)}</td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>
    </div>
  );
};

export default DetailedModal;
